var items = $input.all();
var results = [];
var now = new Date().toISOString();
var vendorKeywords = ['tribal', 'ellucian', 'unit4', 'technologyone', 'aptem', 'sits', 'banner', 'peoplesoft', 'workday', 'salesforce education', 'oneacademic', 'digital campus', 'thesis', 'blackbaud'];
var hermKeywords = ['herm', 'higher education reference model', 'reference model', 'capability model', 'process model'];
var productKeywords = ['launch', 'release', 'new feature', 'partnership', 'acquisition', 'integration', 'platform'];
var regulatoryKeywords = ['ofs', 'office for students', 'regulation', 'hesa', 'quality', 'condition', 'compliance', 'tef', 'ref'];
var aiEdKeywords = ['artificial intelligence', 'machine learning', 'chatgpt', 'llm', 'automation', 'marking', 'assessment ai'];

for (var i = 0; i < items.length; i++) {
  var data = items[i].json;
  var title = data.title || 'Untitled';
  var link = data.link || data.url || data.guid || '';
  var summary = (data.contentSnippet || data.content || data.description || '').replace(/<[^>]*>/g, '').trim();
  if (summary.length > 600) summary = summary.substring(0, 597) + '...';
  var source = data.creator || data.author || 'HE Source';
  var text = (title + ' ' + summary).toLowerCase();
  var category = 'sector-news';
  var priority = 3;
  var matchedVendors = [];
  for (var v = 0; v < vendorKeywords.length; v++) { if (text.indexOf(vendorKeywords[v]) >= 0) matchedVendors.push(vendorKeywords[v]); }
  if (matchedVendors.length > 0) { category = 'vendor-intel'; priority = 1; }
  for (var h = 0; h < hermKeywords.length; h++) { if (text.indexOf(hermKeywords[h]) >= 0) { category = 'herm-model'; priority = 1; break; } }
  if (category === 'sector-news') { for (var p = 0; p < productKeywords.length; p++) { if (text.indexOf(productKeywords[p]) >= 0) { category = 'product-update'; priority = 2; break; } } }
  if (category === 'sector-news') { for (var r = 0; r < regulatoryKeywords.length; r++) { if (text.indexOf(regulatoryKeywords[r]) >= 0) { category = 'regulatory'; priority = 2; break; } } }
  if (category === 'sector-news') { for (var a = 0; a < aiEdKeywords.length; a++) { if (text.indexOf(aiEdKeywords[a]) >= 0) { category = 'ai-in-education'; priority = 2; break; } } }
  results.push({ json: { title: title, url: link, summary: summary, source: source, discovered_at: now, category: category, priority: priority, matched_vendors: matchedVendors.join(', '), signal_type: 'he-landscape' } });
}
var seen = {};
var unique = [];
for (var j = 0; j < results.length; j++) {
  var u = results[j].json.url || results[j].json.title;
  if (u && !seen[u]) { seen[u] = true; unique.push(results[j]); }
}
unique.sort(function(a, b) { return a.json.priority - b.json.priority; });
return unique.length > 0 ? unique : [{ json: { title: 'No HE landscape updates this week', url: '', summary: '', source: 'scanner', category: 'none', priority: 9, matched_vendors: '', signal_type: 'he-landscape', discovered_at: now } }];

var items = $('Classify HE Signals').all();
var now = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
var groups = {};
for (var i = 0; i < items.length; i++) {
  var cat = items[i].json.category || 'other';
  if (!groups[cat]) groups[cat] = [];
  groups[cat].push(items[i].json);
}
var labels = { 'herm-model': 'HERM Model Updates (Priority)', 'vendor-intel': 'Vendor Intelligence', 'product-update': 'Product Launches & Updates', 'regulatory': 'Regulatory & Compliance (OfS, HESA)', 'ai-in-education': 'AI in Higher Education', 'sector-news': 'Sector News & Analysis', 'none': 'No new items' };
var colors = { 'herm-model': '#8e44ad', 'vendor-intel': '#e67e22', 'product-update': '#27ae60', 'regulatory': '#c0392b', 'ai-in-education': '#2980b9', 'sector-news': '#34495e', 'none': '#bdc3c7' };
var html = '<div style="font-family:Arial,sans-serif;max-width:750px;margin:0 auto;"><h1 style="color:#2c3e50;">HERM & HE Academic Management Landscape</h1>';
html += '<p style="color:#666;">Weekly brief - ' + now + ' - ' + items.length + ' signals</p><hr>';
html += '<div style="background:#ecf0f1;padding:12px;border-radius:5px;margin-bottom:20px;"><strong>Coverage:</strong> vendor moves, HERM updates, OfS/HESA policy, product launches, AI adoption</div>';
var categoryOrder = ['herm-model', 'vendor-intel', 'product-update', 'ai-in-education', 'regulatory', 'sector-news', 'none'];
for (var c = 0; c < categoryOrder.length; c++) {
  var catKey = categoryOrder[c];
  if (!groups[catKey] || groups[catKey].length === 0) continue;
  var entries = groups[catKey];
  var color = colors[catKey] || '#34495e';
  html += '<h2 style="color:' + color + ';border-bottom:2px solid ' + color + ';padding-bottom:5px;">' + (labels[catKey] || catKey) + ' (' + entries.length + ')</h2><ul style="list-style:none;padding:0;">';
  for (var e = 0; e < entries.length; e++) {
    html += '<li style="margin-bottom:12px;padding:10px;background:#f9f9f9;border-left:3px solid ' + color + ';border-radius:4px;">';
    if (entries[e].url) html += '<strong><a href="' + entries[e].url + '" style="color:' + color + ';">' + entries[e].title + '</a></strong>';
    else html += '<strong>' + entries[e].title + '</strong>';
    if (entries[e].matched_vendors) html += ' <span style="background:#fff3cd;color:#856404;padding:2px 6px;border-radius:3px;font-size:0.8em;">Vendors: ' + entries[e].matched_vendors + '</span>';
    if (entries[e].summary) html += '<br><span style="color:#555;font-size:0.9em;">' + entries[e].summary.substring(0, 280) + '</span>';
    html += '<br><small style="color:#999;">Source: ' + entries[e].source + '</small></li>';
  }
  html += '</ul>';
}
html += '<hr><p style="color:#999;font-size:0.8em;">HERM Landscape Scanner - Workhorse</p></div>';
return [{ json: { subject: 'HERM & HE Management Weekly - ' + now, html: html } }];
